+function drawTorchGlow(ctx: CanvasRenderingContext2D, x: number, y: number, radius: number, intensity: number) {
+  // Create a warm orange-yellow radial gradient with alpha fading out
+  const gradient = ctx.createRadialGradient(x, y, 0, x, y, radius);
+  gradient.addColorStop(0, `rgba(255, 180, 60, ${0.3 * intensity})`);
+  gradient.addColorStop(0.4, `rgba(255, 140, 20, ${0.15 * intensity})`);
+  gradient.addColorStop(1, `rgba(255, 100, 0, 0)`);
+  ctx.fillStyle = gradient;
+  ctx.beginPath();
+  ctx.arc(x, y, radius, 0, Math.PI * 2);
+  ctx.fill();
+}
+
+function drawTorch(ctx: CanvasRenderingContext2D, x: number, y: number, frame: number) {
+  // Draw torch body
+  ctx.fillStyle = '#4a4a58'; ctx.fillRect(x + 1, y + 10, 6, 4); ctx.fillRect(x + 5, y + 8, 3, 8);
+  ctx.fillStyle = '#4a2810'; ctx.fillRect(x + 2, y + 4, 4, 14);
+  ctx.fillStyle = '#5c3418'; ctx.fillRect(x + 3, y + 5, 2, 12);
+
+  // Flicker offsets for flame shapes
+  const f1 = Math.sin(frame * 0.2) * 2, f2 = Math.cos(frame * 0.25) * 1.5, f3 = Math.sin(frame * 0.3 + 1);
+
+  // Draw flame shapes with flicker offsets
+  ctx.fillStyle = '#c05020'; ctx.fillRect(x + f2, y - 4, 8, 10);
+  ctx.fillStyle = '#e08030'; ctx.fillRect(x + 1 + f1, y - 6, 6, 10);
+  ctx.fillStyle = '#f0b040'; ctx.fillRect(x + 2 + f3, y - 7, 4, 8);
+  ctx.fillStyle = '#ffe890'; ctx.fillRect(x + 3, y - 5, 2, 4);
+
+  // Flicker radius ±2px around base radius 24 for glow
+  const baseRadius = 24;
+  const flickerRadius = baseRadius + Math.sin(frame * 0.15) * 2;
+  drawTorchGlow(ctx, x + 4, y, flickerRadius, 1);
+}
