+function drawRoomLighting(ctx: CanvasRenderingContext2D, type: CharacterType, x: number, y: number, w: number, h: number) {
+  const cs = Math.max(w, h) * 0.4;
+  // Darken corners more strongly with radial gradients fading out
+  for (const [cx, cy] of [[x, y], [x + w, y], [x, y + h], [x + w, y + h]] as [number, number][]) {
+    const g = ctx.createRadialGradient(cx, cy, 0, cx, cy, cs);
+    g.addColorStop(0, 'rgba(0,0,0,0.35)');
+    g.addColorStop(1, 'rgba(0,0,0,0)');
+    ctx.fillStyle = g;
+    ctx.fillRect(Math.max(x, cx - cs), Math.max(y, cy - cs), cs * 2, cs * 2);
+  }
+  // Additional subtle warm light for healer or king
+  if (type === 'healer' || type === 'king') {
+    const g = ctx.createRadialGradient(x + w / 2, y + h * 0.5, 0, x + w / 2, y + h * 0.5, w * 0.45);
+    g.addColorStop(0, 'rgba(255, 200, 100, 0.04)');
+    g.addColorStop(1, 'rgba(255, 200, 100, 0)');
+    ctx.fillStyle = g;
+    ctx.fillRect(x, y, w, h);
+  }
+}
